import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { translations } from "../utils/translations";

// ─────────────────────────────────────────────
// Visual self-check cards (English labels only —
// images are universal, answers use t.saOptions)
// ─────────────────────────────────────────────
const CARDS = [
  {
    id: "lump",
    emoji: "🔍",
    title: "Lump or Thickening",
    description: "A hard or unusual lump in the breast or underarm area that wasn't there before.",
    image: "data:image/jpeg;base64,",
  },
  {
    id: "shape",
    emoji: "📐",
    title: "Change in Shape or Size",
    description: "Visible swelling, asymmetry, or change in the size of one or both breasts.",
    image: "data:image/jpeg;base64,",
  },
  {
    id: "skin",
    emoji: "🌿",
    title: "Skin Changes",
    description: "Dimpling, puckering, redness, or skin that looks like an orange peel.",
    image: "data:image/jpeg;base64,",
  },
  {
    id: "nipple",
    emoji: "💧",
    title: "Nipple Changes or Discharge",
    description: "Nipple turning inward, unusual discharge, or changes in nipple appearance.",
    image: "data:image/jpeg;base64,",
  },
  {
    id: "pain",
    emoji: "⚡",
    title: "Persistent Breast Pain",
    description: "Ongoing pain or tenderness in the breast or underarm that doesn't go away.",
    image: "data:image/jpeg;base64,",
  },
  {
    id: "exam",
    emoji: "🩺",
    title: "Never Had a Screening",
    description: "Not having had a mammogram, ultrasound, or clinical breast exam in over 2 years.",
    image: "data:image/jpeg;base64,",
  },
];

// Scoring: 0 = No issue, 1 = Not sure, 2 = Yes
const SCORE_MAP = [0, 1, 2];

export default function SelfAssessment() {
  const navigate = useNavigate();
  const lang = localStorage.getItem("lang") || "en";
  const t = translations[lang] || translations["en"];

  // answers: { cardId: optionIndex (0|1|2) }
  const [answers, setAnswers] = useState({});

  const handleSelect = (cardId, optionIndex) => {
    setAnswers((prev) => ({ ...prev, [cardId]: optionIndex }));
  };

  const allAnswered = CARDS.every((c) => answers[c.id] !== undefined);

  const handleNext = () => {
    // Calculate total score
    const score = CARDS.reduce((sum, c) => sum + (SCORE_MAP[answers[c.id]] ?? 0), 0);

    // Build detail object for storage
    const data = CARDS.map((c) => ({
      id:     c.id,
      title:  c.title,
      answer: t.saOptions[answers[c.id]],
      score:  SCORE_MAP[answers[c.id]] ?? 0,
    }));

    localStorage.setItem("self_score",      score);
    localStorage.setItem("self_assessment", JSON.stringify(data));

    navigate("/questionnaire");
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-pink-50 via-rose-50 to-pink-100 flex flex-col px-5 py-8">
      <div className="max-w-sm mx-auto w-full">

        {/* Header */}
        <div className="flex items-center justify-between mb-2">
          <button
            onClick={() => navigate("/language")}
            className="text-pink-400 hover:text-pink-600 text-sm font-medium"
          >
            {t.back}
          </button>
          <span className="text-pink-600 font-extrabold text-lg">HerHealth AI 💖</span>
          <div className="w-12" />
        </div>

        {/* Title */}
        <h2 className="text-2xl font-extrabold text-pink-700 mt-5 mb-1">{t.selfTitle}</h2>
        <p className="text-gray-400 text-sm mb-6">{t.selfSubtitle}</p>

        {/* Cards */}
        <div className="flex flex-col gap-5">
          {CARDS.map((card) => (
            <div
              key={card.id}
              className="bg-white rounded-3xl shadow-sm border border-pink-100 overflow-hidden"
            >
              {/* Image */}
              <div className="relative w-full h-36 overflow-hidden bg-pink-50">
                <img
                  src={card.image}
                  alt={card.title}
                  className="w-full h-full object-cover opacity-80"
                  onError={(e) => {
                    // fallback if image fails to load
                    e.target.style.display = "none";
                  }}
                />
                {/* Emoji badge over image */}
                <div className="absolute top-3 left-3 bg-white/80 backdrop-blur-sm rounded-xl px-3 py-1 flex items-center gap-1.5 shadow-sm">
                  <span className="text-xl">{card.emoji}</span>
                  <span className="text-pink-700 font-bold text-sm">{card.title}</span>
                </div>
              </div>

              {/* Description */}
              <div className="px-5 pt-4 pb-2">
                <p className="text-gray-500 text-sm leading-relaxed">{card.description}</p>
              </div>

              {/* Options */}
              <div className="flex flex-col gap-2 px-5 pb-5 pt-3">
                {t.saOptions.map((opt, idx) => {
                  const isSelected = answers[card.id] === idx;
                  const colors = [
                    isSelected ? "bg-green-100 border-green-400 text-green-700" : "bg-white border-pink-100 text-gray-500 hover:border-green-300",
                    isSelected ? "bg-yellow-100 border-yellow-400 text-yellow-700" : "bg-white border-pink-100 text-gray-500 hover:border-yellow-300",
                    isSelected ? "bg-rose-100 border-rose-400 text-rose-700"   : "bg-white border-pink-100 text-gray-500 hover:border-rose-300",
                  ];
                  return (
                    <button
                      key={idx}
                      onClick={() => handleSelect(card.id, idx)}
                      className={`w-full text-left px-4 py-3 rounded-xl border-2 text-sm font-semibold transition-all duration-150 active:scale-95 ${colors[idx]}`}
                    >
                      <span className="mr-2">{["✅", "🤔", "⚠️"][idx]}</span>
                      {opt}
                    </button>
                  );
                })}
              </div>
            </div>
          ))}
        </div>

        {/* Progress hint */}
        <p className="text-center text-gray-400 text-xs mt-4 mb-2">
          {Object.keys(answers).length} / {CARDS.length} answered
        </p>

        {/* Next Button */}
        <button
          onClick={handleNext}
          disabled={!allAnswered}
          className={`w-full py-4 rounded-2xl font-bold text-lg mt-2 mb-3 transition-all duration-200 shadow-md
            ${allAnswered
              ? "bg-pink-500 hover:bg-pink-600 active:scale-95 text-white"
              : "bg-pink-200 text-pink-300 cursor-not-allowed"
            }`}
        >
          {t.saNext}
        </button>

        <p className="text-center text-gray-300 text-xs mb-8">{t.saPrivacy}</p>
      </div>
    </div>
  );
}